                  Constant *C = nullptr;
                  if (Succ == TrueSuccessor)
                    C = ConstantInt::get(Type::getInt64Ty(Trunc->getContext()), 1);
                  else if (Succ == FalseSuccessor)
                    C = ConstantInt::get(Type::getInt64Ty(Trunc->getContext()), 0);
                  if (C) {
                    // Only replace if the pointer operand is the same.
                    if (Store->getPointerOperand() == getUnderlyingObject(Store->getPointerOperand())) {
                      Store->setValueOperand(C);
                      Changed = true;
                    }
                  }
                }
              }
            }
          }
        }
      }

